dataSet.query:
ВЫБРАТЬ Пользователи.Ссылка КАК Пользователь ПОМЕСТИТЬ Пользователи ИЗ Справочник.Пользователи КАК Пользователи {ГДЕ Пользователи.Ссылка.* КАК Пользователь}
ОБЪЕДИНИТЬ
ВЫБРАТЬ ГруппыПользователейСостав.Ссылка ИЗ Справочник.ГруппыПользователей.Состав КАК ГруппыПользователейСостав {ГДЕ ГруппыПользователейСостав.Пользователь.*} ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ Пользователи.Пользователь КАК Пользователь, НазначенныеЗаместители.Состояние КАК Состояние, &ТекстВизы КАК ОбластьДанных, ПраваНаВизирование.Виза КАК Виза, ЕСТЬNULL(НазначенныеЗаместители.ПользовательскоеУсловие, ПраваНаВизирование.ПользовательскоеУсловие) КАК ПользовательскоеУсловие, ПраваНаВизирование.ПользовательскоеУсловие КАК ПользовательскоеУсловиеОсновное, НазначенныеЗаместители.Заместитель КАК Заместитель, ВЫБОР КОГДА НазначенныеЗаместители.Заместитель.ПометкаУдаления ИЛИ НазначенныеЗаместители.Заместитель.Недействителен ТОГДА ИСТИНА ИНАЧЕ ЛОЖЬ КОНЕЦ КАК НеактивныйЗаместитель, НазначенныеЗаместители.Заместитель КАК ЗаместительПредыдущий, ВЫБОР КОГДА НЕ ПраваЗаместителей.Замещаемый ЕСТЬ NULL ТОГДА ИСТИНА ИНАЧЕ ЛОЖЬ КОНЕЦ КАК ЗамАктивен, НазначенныеЗаместители.ДатаНачала КАК ДатаНачала, НазначенныеЗаместители.ДатаОкончания КАК ДатаОкончания, ЛОЖЬ КАК Изменено, NULL КАК РольИсполнителя, NULL КАК ОбъектАдресации_1, NULL КАК ОбъектАдресации_2, NULL КАК ОбъектАдресации_3, НазначенныеЗаместители.ПередаватьПраваРЛС КАК ПередаватьПраваРЛС {ВЫБРАТЬ Состояние.*, ОбластьДанных, Виза.*, ПользовательскоеУсловие.*, Заместитель.*, ЗаместительПредыдущий.*, ЗамАктивен, ДатаНачала, ДатаОкончания, Изменено, РольИсполнителя, ОбъектАдресации_1, ОбъектАдресации_2, ОбъектАдресации_3, ПередаватьПраваРЛС, Пользователь} ИЗ РегистрСведений.бит_ПраваУстановкиВиз КАК ПраваНаВизирование ЛЕВОЕ СОЕДИНЕНИЕ РегистрСведений.бит_НазначенныеЗаместители КАК НазначенныеЗаместители ЛЕВОЕ СОЕДИНЕНИЕ РегистрСведений.бит_ПраваУстановкиВиз КАК ПраваЗаместителей ПО НазначенныеЗаместители.Виза = ПраваЗаместителей.Виза И НазначенныеЗаместители.ПользовательскоеУсловие = ПраваЗаместителей.ПользовательскоеУсловие И НазначенныеЗаместители.Заместитель = ПраваЗаместителей.Пользователь И НазначенныеЗаместители.Пользователь = ПраваЗаместителей.Замещаемый ПО ПраваНаВизирование.Пользователь = НазначенныеЗаместители.Пользователь И ПраваНаВизирование.Виза = НазначенныеЗаместители.Виза И (НазначенныеЗаместители.Состояние <> ЗНАЧЕНИЕ(Перечисление.бит_СостоянияЗаместителей.ЗамещениеЗавершено)) И (ПраваНаВизирование.ПользовательскоеУсловие = НазначенныеЗаместители.ПользовательскоеУсловие ИЛИ ПраваНаВизирование.ПользовательскоеУсловие = ЗНАЧЕНИЕ(Справочник.бит_ПользовательскиеУсловия.ПустаяСсылка)) ВНУТРЕННЕЕ СОЕДИНЕНИЕ Пользователи КАК Пользователи ПО ПраваНаВизирование.Пользователь = Пользователи.Пользователь И (ПраваНаВизирование.Пользователь <> ЗНАЧЕНИЕ(Справочник.ГруппыПользователей.ВсеПользователи)) И (ПраваНаВизирование.Замещаемый = ЗНАЧЕНИЕ(Справочник.Пользователи.ПустаяСсылка) ИЛИ ПраваНаВизирование.Замещаемый = НЕОПРЕДЕЛЕНО) {ГДЕ НазначенныеЗаместители.Состояние.*, (&ТекстВизы) КАК ОбластьДанных, ПраваНаВизирование.Виза.*, ПраваНаВизирование.ПользовательскоеУсловие.*, НазначенныеЗаместители.Заместитель.*, (ВЫБОР КОГДА НЕ ПраваЗаместителей.Замещаемый ЕСТЬ NULL ТОГДА ИСТИНА ИНАЧЕ ЛОЖЬ КОНЕЦ) КАК ЗамАктивен, НазначенныеЗаместители.ДатаНачала, НазначенныеЗаместители.ДатаОкончания, (ЛОЖЬ) КАК Изменено, НазначенныеЗаместители.ПередаватьПраваРЛС}
ОБЪЕДИНИТЬ ВСЕ
ВЫБРАТЬ бит_ИсполнителиЗадач.Исполнитель, бит_НазначенныеЗаместители.Состояние, &ТекстРоли, NULL, NULL, NULL, бит_НазначенныеЗаместители.Заместитель, ВЫБОР КОГДА бит_НазначенныеЗаместители.Заместитель.ПометкаУдаления ИЛИ бит_НазначенныеЗаместители.Заместитель.Недействителен ТОГДА ИСТИНА ИНАЧЕ ЛОЖЬ КОНЕЦ, бит_НазначенныеЗаместители.Заместитель, ВЫБОР КОГДА НЕ бит_ИсполнителиЗадачЗам.Замещаемый ЕСТЬ NULL ТОГДА ИСТИНА ИНАЧЕ ЛОЖЬ КОНЕЦ, бит_НазначенныеЗаместители.ДатаНачала, бит_НазначенныеЗаместители.ДатаОкончания, ЛОЖЬ, бит_ИсполнителиЗадач.РольИсполнителя, бит_ИсполнителиЗадач.ОбъектАдресации_1, бит_ИсполнителиЗадач.ОбъектАдресации_2, бит_ИсполнителиЗадач.ОбъектАдресации_3, бит_НазначенныеЗаместители.ПередаватьПраваРЛС ИЗ РегистрСведений.бит_ИсполнителиЗадач КАК бит_ИсполнителиЗадач ЛЕВОЕ СОЕДИНЕНИЕ РегистрСведений.бит_НазначенныеЗаместители КАК бит_НазначенныеЗаместители ЛЕВОЕ СОЕДИНЕНИЕ РегистрСведений.бит_ИсполнителиЗадач КАК бит_ИсполнителиЗадачЗам ПО бит_НазначенныеЗаместители.Пользователь = бит_ИсполнителиЗадачЗам.Замещаемый И бит_НазначенныеЗаместители.РольИсполнителя = бит_ИсполнителиЗадачЗам.РольИсполнителя И бит_НазначенныеЗаместители.ОбъектАдресации_1 = бит_ИсполнителиЗадачЗам.ОбъектАдресации_1 И бит_НазначенныеЗаместители.ОбъектАдресации_2 = бит_ИсполнителиЗадачЗам.ОбъектАдресации_2 И бит_НазначенныеЗаместители.ОбъектАдресации_3 = бит_ИсполнителиЗадачЗам.ОбъектАдресации_3 И бит_НазначенныеЗаместители.Заместитель = бит_ИсполнителиЗадачЗам.Исполнитель ПО бит_ИсполнителиЗадач.РольИсполнителя = бит_НазначенныеЗаместители.РольИсполнителя И бит_ИсполнителиЗадач.Исполнитель = бит_НазначенныеЗаместители.Пользователь И бит_ИсполнителиЗадач.ОбъектАдресации_1 = бит_НазначенныеЗаместители.ОбъектАдресации_1 И бит_ИсполнителиЗадач.ОбъектАдресации_2 = бит_НазначенныеЗаместители.ОбъектАдресации_2 И бит_ИсполнителиЗадач.ОбъектАдресации_3 = бит_НазначенныеЗаместители.ОбъектАдресации_3 И (бит_НазначенныеЗаместители.Состояние <> ЗНАЧЕНИЕ(Перечисление.бит_СостоянияЗаместителей.ЗамещениеЗавершено)) ГДЕ бит_ИсполнителиЗадач.Замещаемый = ЗНАЧЕНИЕ(Справочник.Пользователи.ПустаяСсылка) И НЕ бит_ИсполнителиЗадач.Исполнитель = ЗНАЧЕНИЕ(Справочник.ГруппыПользователей.ВсеПользователи) {ГДЕ бит_ИсполнителиЗадач.Исполнитель.*, бит_НазначенныеЗаместители.Состояние.*, (&ТекстРоли) КАК ОбластьДанных, бит_НазначенныеЗаместители.Заместитель.*, (ВЫБОР КОГДА НЕ бит_ИсполнителиЗадачЗам.Замещаемый ЕСТЬ NULL ТОГДА ИСТИНА ИНАЧЕ ЛОЖЬ КОНЕЦ) КАК ЗамАктивен, бит_НазначенныеЗаместители.ДатаНачала, бит_НазначенныеЗаместители.ДатаОкончания, (ЛОЖЬ) КАК Изменено, бит_ИсполнителиЗадач.РольИсполнителя.*, бит_ИсполнителиЗадач.ОбъектАдресации_1.*, бит_ИсполнителиЗадач.ОбъектАдресации_2.*, бит_ИсполнителиЗадач.ОбъектАдресации_3.*, бит_НазначенныеЗаместители.ПередаватьПраваРЛС}
ОБЪЕДИНИТЬ ВСЕ
ВЫБРАТЬ РАЗЛИЧНЫЕ Задача.Исполнитель, ЗаместителиПоЗадачам.Состояние, &ТекстЗадачи, NULL, NULL, NULL, ЗаместителиПоЗадачам.Заместитель, ВЫБОР КОГДА ЗаместителиПоЗадачам.Заместитель.ПометкаУдаления ИЛИ ЗаместителиПоЗадачам.Заместитель.Недействителен ТОГДА ИСТИНА ИНАЧЕ ЛОЖЬ КОНЕЦ, ЗаместителиПоЗадачам.Заместитель, NULL, ЗаместителиПоЗадачам.ДатаНачала, ЗаместителиПоЗадачам.ДатаОкончания, ЛОЖЬ, NULL, NULL, NULL, NULL, NULL ИЗ Задача.бит_Задача КАК Задача ЛЕВОЕ СОЕДИНЕНИЕ РегистрСведений.бит_ЗаместителиПоЗадачам КАК ЗаместителиПоЗадачам ПО Задача.Исполнитель = ЗаместителиПоЗадачам.Пользователь ГДЕ Задача.Исполнитель <> ЗНАЧЕНИЕ(Справочник.Пользователи.ПустаяСсылка)
